@namespace sv_7f4b49bcc7964b7d95adf0cd25379337.Components.Pages.Catalog

<div class="catalog-toolbar">
    <div class="toolbar-sort">
        <label for="sort-select">Sort by:</label>
        <select id="sort-select" value="@CurrentSort" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <div class="toolbar-info">
        @if (TotalCount > 0)
        {
            <span>Showing @StartItem–@EndItem of @TotalCount products</span>
        }
    </div>
</div>

@code {
    [Parameter]
    public string CurrentSort { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; } = 1;

    [Parameter]
    public int PageSize { get; set; } = 12;

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private int StartItem => TotalCount == 0 ? 0 : (Page - 1) * PageSize + 1;
    private int EndItem => Math.Min(Page * PageSize, TotalCount);

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@namespace sv_7f4b49bcc7964b7d95adf0cd25379337.Components.Pages.Catalog

<nav class="catalog-pagination" aria-label="Product pagination">
    <button class="btn-page"
            disabled="@(CurrentPage <= 1)"
            @onclick="@(() => GoToPage(CurrentPage - 1))">
        Previous
    </button>

    @for (int i = 1; i <= TotalPages; i++)
    {
        var pageNum = i;
        <button class="btn-page @(pageNum == CurrentPage ? "active" : "")"
                @onclick="@(() => GoToPage(pageNum))">
            @pageNum
        </button>
    }

    <button class="btn-page"
            disabled="@(CurrentPage >= TotalPages)"
            @onclick="@(() => GoToPage(CurrentPage + 1))">
        Next
    </button>
</nav>

@code {
    [Parameter]
    public int CurrentPage { get; set; } = 1;

    [Parameter]
    public int TotalPages { get; set; } = 1;

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

@page "/catalog"
@namespace sv_7f4b49bcc7964b7d95adf0cd25379337.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-page">
    <CatalogFilters Categories="_categories"
                    OnFilterApplied="HandleFilterApplied"
                    OnFilterCleared="HandleFilterCleared" />

    <main class="catalog-main">
        @if (_isLoading)
        {
            <div class="catalog-loading">
                <p>Loading products...</p>
            </div>
        }
        else if (_errorMessage is not null)
        {
            <div class="catalog-error">
                <p>@_errorMessage</p>
                <button @onclick="LoadProducts">Retry</button>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="catalog-empty">
                <p>No products found matching your criteria.</p>
            </div>
        }
        else
        {
            <CatalogToolbar CurrentSort="@_sortBy"
                            TotalCount="_result.TotalCount"
                            Page="_currentPage"
                            PageSize="PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="_currentPage"
                               TotalPages="_totalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </main>
</div>

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> _categories = [];
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private bool _isLoading;
    private string? _errorMessage;

    private int _totalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadCategories();
        await LoadProducts();
    }

    private async Task LoadCategories()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            _categories = [];
        }
    }

    private async Task LoadProducts()
    {
        _isLoading = true;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load products: {ex.Message}";
            _result = null;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        await Task.CompletedTask;
    }
}

